import{_ as s,o as n,c as e,a4 as p}from"./chunks/framework.BDOgl-CJ.js";const h=JSON.parse('{"title":"反向传播：模型是怎么学习的","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/backpropagation.md","filePath":"ai-learning-notes/backpropagation.md","lastUpdated":1779095553000}'),t={name:"ai-learning-notes/backpropagation.md"};function o(i,a,l,r,c,d){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="反向传播-模型是怎么学习的" tabindex="-1">反向传播：模型是怎么学习的 <a class="header-anchor" href="#反向传播-模型是怎么学习的" aria-label="Permalink to &quot;反向传播：模型是怎么学习的&quot;">​</a></h1><blockquote><p>记录于 2026-05-18，对话整理</p></blockquote><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>模型输出错了 → 算出错多少（误差）→ 从后往前，每个参数算&quot;我该调多少&quot; → 全部微调一点 → 重复百亿次</p><hr><h2 id="一个具体例子" tabindex="-1">一个具体例子 <a class="header-anchor" href="#一个具体例子" aria-label="Permalink to &quot;一个具体例子&quot;">​</a></h2><p><strong>任务</strong>：预测&quot;猫 在 屋顶 ___&quot;的下一个词</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正确答案：跑   （这个词在训练文本里就有，是真实数据）</span></span>
<span class="line"><span>模型输出：睡   概率分布 [睡:0.6, 跑:0.3, 飞:0.1]</span></span></code></pre></div><p><strong>计算误差（Loss）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正确答案 = &quot;跑&quot; 的概率应该是 1.0</span></span>
<span class="line"><span>模型预测   &quot;跑&quot; 的概率是     0.3</span></span>
<span class="line"><span>误差 = -log(0.3) ≈ 1.2    （越接近1误差越小）</span></span></code></pre></div><hr><h2 id="从后往前算-链式法则" tabindex="-1">从后往前算：链式法则 <a class="header-anchor" href="#从后往前算-链式法则" aria-label="Permalink to &quot;从后往前算：链式法则&quot;">​</a></h2><p>误差从输出层往前&quot;传&quot;，每一层都算自己对误差的贡献：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>误差 1.2</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ 全连接层（输出层）：我的权重该调多少？→ 算出 Δ全连接</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ 第N个注意力层：我该调多少？→ 算出 Δ注意力</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ ...</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼ Embedding 层：&quot;猫&quot;那行要调多少？→ 算出 Δ猫的向量</span></span></code></pre></div><p>这就是<strong>链式法则</strong>：后面层的误差乘上当前层的斜率 = 当前层的调整量。</p><hr><h2 id="锅怎么分" tabindex="-1">锅怎么分 <a class="header-anchor" href="#锅怎么分" aria-label="Permalink to &quot;锅怎么分&quot;">​</a></h2><p>&quot;猫 在 屋顶&quot;这三个词都参与了预测，所以：</p><ul><li>注意力权重分析：模型主要在看哪个词？</li><li>看得多的词，承担更多的&quot;锅&quot;</li><li>每个词的 Embedding 行，根据&quot;参与程度&quot;各自调整</li></ul><p>不是某一个词单独背锅，是<strong>按贡献比例分担误差</strong>。</p><hr><h2 id="正确答案从哪来" tabindex="-1">正确答案从哪来 <a class="header-anchor" href="#正确答案从哪来" aria-label="Permalink to &quot;正确答案从哪来&quot;">​</a></h2><p>训练用的是<strong>真实文本</strong>（自监督学习），不需要人工标注：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>训练数据（互联网文本）：</span></span>
<span class="line"><span>&quot;猫 在 屋顶 跑 来 跑 去&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>模型看到：猫 在 屋顶 [?]   → 正确答案就是 &quot;跑&quot;</span></span>
<span class="line"><span>模型看到：在 屋顶 跑 [?]   → 正确答案就是 &quot;来&quot;</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>每一句话都能自动生成无数个&quot;题目+答案&quot;对，这就是为什么 LLM 可以用海量数据训练，不需要人工标注每一条。</p><hr><h2 id="和我们工作的关系" tabindex="-1">和我们工作的关系 <a class="header-anchor" href="#和我们工作的关系" aria-label="Permalink to &quot;和我们工作的关系&quot;">​</a></h2><p>作为 LLM 应用工程师，不需要手写反向传播。但理解它有用：</p><ul><li>知道为什么&quot;训练数据质量&quot;很重要（垃圾数据 → 错误的梯度信号）</li><li>理解为什么模型在罕见知识上更容易出错（训练数据少 → 那块参数没调好）</li><li>知道 fine-tune / RAG 各自在哪个层面起作用</li></ul>`,30)])])}const g=s(t,[["render",o]]);export{h as __pageData,g as default};
